/**
 * Code node protegido — procura e parseia tabelas Markdown em qualquer campo string.
 * Saída:
 *  - Para cada linha de tabela encontrada: { json: { success: true, ...rowFields, _sourceItemIndex, originalFileId } }
 *  - Se não encontrou: { json: { success: false, errorMessage, _sourceItemIndex, originalFileId } }
 */

function findTablesInString(s) {
  const tables = [];
  const re = /(^\|[^\n]*\|\s*\n^\|[ \t\-:|]*\|\s*\n(?:^\|[^\n]*\|\s*\n?)+)/gim;
  let m;
  while ((m = re.exec(s)) !== null) {
    tables.push(m[1]);
  }
  return tables;
}

function parseMarkdownTable(raw) {
  const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length);
  if (lines.length < 2) return [];
  let dividerIndex = -1;
  for (let i = 0; i < lines.length; i++) {
    if (/^\|?\s*[:\-]+\s*(\|[:\-]+\s*)*\|?$/.test(lines[i].replace(/\s/g, ''))) {
      dividerIndex = i;
      break;
    }
  }
  if (dividerIndex === -1) dividerIndex = 1;
  const headerLine = lines[0];
  const dataLines = lines.slice(dividerIndex + 1);
  const rawHeaders = headerLine.split('|').map(h => h.trim()).filter(h => h !== '');

  const normalize = (h) => h.toLowerCase().replace(/\s+/g, '_').replace(/[^\w_]/g, '');

  const out = [];
  for (let line of dataLines) {
    if (!/^\|/.test(line)) continue;
    const cols = line.split('|').map(c => c.trim());
    const obj = {};
    for (let i = 0; i < rawHeaders.length; i++) {
      const h = rawHeaders[i];
      const key = normalize(h);
      let val = cols[i+1] !== undefined ? cols[i+1] : '';
      if (/telefone|tel|phone|celular/i.test(h)) {
        val = String(val).replace(/[^\d+]/g, '');
      } else {
        val = String(val).trim();
      }
      obj[key] = val;
    }
    out.push(obj);
  }
  return out;
}

// main
const outputs = [];

for (let idx = 0; idx < items.length; idx++) {
  try {
    const it = items[idx].json;
    // tenta achar um id de arquivo comum (id, fileId, driveId)
    const originalFileId = it.id || it.fileId || it.driveId || it.originalFileId || null;

    let foundAny = false;

    // percorre recursivamente valores string do objeto para procurar tabelas
    const stack = [it];
    while (stack.length) {
      const node = stack.pop();
      if (node && typeof node === 'object') {
        for (const v of Object.values(node)) {
          if (typeof v === 'string') {
            const tables = findTablesInString(v);
            if (tables.length) {
              foundAny = true;
              for (const tbl of tables) {
                // parse com try/catch por tabela (proteção extra)
                try {
                  const parsed = parseMarkdownTable(tbl);
                  for (const row of parsed) {
                    // inclui metadados úteis
                    row._sourceItemIndex = idx;
                    row.originalFileId = originalFileId;
                    outputs.push({ json: Object.assign({ success: true }, row) });
                  }
                } catch (eTbl) {
                  // se parse falhar, marca erro mas não quebra
                  outputs.push({
                    json: {
                      success: false,
                      errorMessage: 'Erro ao parsear tabela: ' + (eTbl.message || 'unknown'),
                      _sourceItemIndex: idx,
                      originalFileId
                    }
                  });
                }
              }
            }
          } else if (v && typeof v === 'object') {
            stack.push(v);
          }
        }
      }
    }

    if (!foundAny) {
      // não encontrou tabela: retorna item marcado como erro para branch do IF
      outputs.push({
        json: {
          success: false,
          errorMessage: 'Nenhuma tabela Markdown encontrada nos campos string do item.',
          _sourceItemIndex: idx,
          originalFileId
        }
      });
    }

  } catch (err) {
    // captura qualquer erro imprevisto e retorna item de erro (não quebra o flow)
    outputs.push({
      json: {
        success: false,
        errorMessage: 'Erro inesperado no node Code: ' + (err.message || 'unknown'),
        _sourceItemIndex: idx,
        originalFileId: (items[idx] && items[idx].json && (items[idx].json.id || items[idx].json.fileId)) || null
      }
    });
  }
}

return outputs;

